<?php
namespace App\Domain\GameHome\Media;use App\Domain\Media\MediaAssetService;use App\Domain\Media\MediaAssetType;use App\Models\GameHomeCard;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Illuminate\Support\Str;use Throwable;
final class GameHomeCardBannerService{const DISK='public';const MAX_BYTES=5242880;private $media;public function __construct(MediaAssetService $media){$this->media=$media;}public function replace(GameHomeCard $card,UploadedFile $file){$info=$this->inspect($file);$root='game-assets/home-cards/'.date('Y/m').'/'.Str::uuid();$path=$root.'/banner.'.$info['extension'];Storage::disk(self::DISK)->put($path,file_get_contents($file->getRealPath()));try{$result=$this->media->replacePrimary($card,['asset_type'=>MediaAssetType::HOME_CARD_BANNER,'disk'=>self::DISK,'path'=>$path,'mime_type'=>$info['mime'],'width'=>1200,'height'=>400,'file_size'=>(int)$file->getSize(),'metadata'=>['home_card_banner_version'=>1,'original_name'=>$file->getClientOriginalName(),'ratio'=>'3:1'],'sort_order'=>0]);}catch(Throwable $e){Storage::disk(self::DISK)->deleteDirectory($root);throw$e;}if($result['previous'])Storage::disk($result['previous']->disk)->delete($result['previous']->path);return$result['asset'];}public function delete(GameHomeCard $card){$asset=$this->media->deletePrimary($card,MediaAssetType::HOME_CARD_BANNER);if($asset)Storage::disk($asset->disk)->delete($asset->path);}public function deleteCard(GameHomeCard $card){$assets=$card->mediaAssets()->get();$paths=$assets->map(function($a){return[$a->disk,$a->path];})->all();$card->delete();foreach($paths as$path)Storage::disk($path[0])->delete($path[1]);}private function inspect(UploadedFile $file){if(!$file->isValid()||(int)$file->getSize()>self::MAX_BYTES)throw new GameHomeCardBannerException('El banner no es válido o supera 5 MB.');$info=@getimagesize($file->getRealPath());if(!$info||(int)$info[0]!==1200||(int)$info[1]!==400)throw new GameHomeCardBannerException('El banner debe medir exactamente 1200 × 400 px.');$map=['image/png'=>'png','image/jpeg'=>'jpg','image/webp'=>'webp'];$mime=isset($info['mime'])?$info['mime']:null;if(!isset($map[$mime]))throw new GameHomeCardBannerException('Solo se permiten banners PNG, JPEG o WebP.');$functions=['image/png'=>'imagecreatefrompng','image/jpeg'=>'imagecreatefromjpeg','image/webp'=>'imagecreatefromwebp'];$image=@call_user_func($functions[$mime],$file->getRealPath());if(!$image)throw new GameHomeCardBannerException('El banner está corrupto.');imagedestroy($image);return['mime'=>$mime,'extension'=>$map[$mime]];}}
